import { useState, useEffect, useMemo } from 'react';
import { studentService } from '~/services/student.service';
import { useTable } from '~/hooks/useTable';
import { useModal } from '~/hooks/useModal';
import { useForm } from '~/hooks/useForm';
import type { Student } from '~/types/student';
import type { SelectOption } from '~/types/common';
import { UserGroupIcon, MagnifyingGlassIcon, FunnelIcon, PencilIcon, TrashIcon } from '@heroicons/react/24/outline';
import { Button, Input, Select, Table, Badge, Card, Pagination, Modal, Toast } from '~/components/ui';
import type { ToastType } from '~/components/ui/Toast';
import {
  STATUS_CONFIG,
  TRINH_DO_OPTIONS,
  GIOI_TINH_OPTIONS,
} from '~/constants/student.constants';

export function meta() {
  return [
    { title: "Danh sách học viên - VMU Training" },
    { name: "description", content: "Quản lý thông tin học viên thạc sỹ" },
  ];
}

export default function Students() {
  // ============================================
  // STATE & HOOKS
  // ============================================
  const [nganhOptions, setNganhOptions] = useState<SelectOption[]>([{ value: '', label: 'Tất cả' }]);
  const [trinhDoOptions, setTrinhDoOptions] = useState<SelectOption[]>(TRINH_DO_OPTIONS);
  const [namVaoOptions, setNamVaoOptions] = useState<SelectOption[]>([]);
  const [namVao, setNamVao] = useState<number>(new Date().getFullYear());
  const [maNganh, setMaNganh] = useState<string>('');

  const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const createModal = useModal();
  const editModal = useModal();
  const deleteModal = useModal();

  const {
    data: students,
    isLoading,
    error,
    meta,
    page,
    perPage,
    search,
    filters,
    handlePageChange,
    handlePerPageChange,
    handleSearch,
    handleFilter,
    handleClearFilters,
    refresh,
  } = useTable<Student>({
    fetchData: studentService.getStudentsPaginated,
    initialPage: 1,
    initialPerPage: 20,
    initialFilters: {
      namVao: new Date().getFullYear(),
      maNganh: '',
    },
  });

  // ============================================
  // FORM SETUP
  // ============================================
  const getInitialFormValues = (student?: Student | null): Partial<Student> => {
    if (student) {
      return {
        maHV: student.maHV,
        hoDem: student.hoDem,
        ten: student.ten,
        ngaySinh: student.ngaySinh,
        gioiTinh: student.gioiTinh,
        soGiayToTuyThan: student.soGiayToTuyThan || '',
        dienThoai: student.dienThoai,
        email: student.email,
        quocTich: student.quocTich || 'Việt Nam',
        danToc: student.danToc || 'Kinh',
        tonGiao: student.tonGiao || 'Không',
        maTrinhDoDaoTao: student.maTrinhDoDaoTao,
        maNganh: student.maNganh,
        trangThai: student.trangThai,
        ngayNhapHoc: student.ngayNhapHoc,
        namVaoTruong: student.namVaoTruong,
      };
    }

    return {
      maHV: '',
      hoDem: '',
      ten: '',
      ngaySinh: '',
      gioiTinh: 'Nam',
      soGiayToTuyThan: '',
      dienThoai: '',
      email: '',
      quocTich: 'Việt Nam',
      danToc: 'Kinh',
      tonGiao: 'Không',
      maTrinhDoDaoTao: '',
      maNganh: '',
      trangThai: 'DangHoc' as any,
      ngayNhapHoc: new Date().toISOString().split('T')[0],
      namVaoTruong: new Date().getFullYear(),
    };
  };

  const validateForm = (values: Partial<Student>): Record<string, string> => {
    const errors: Record<string, string> = {};
    if (!values.maHV?.trim()) errors.maHV = 'Mã học viên là bắt buộc';
    if (!values.hoDem?.trim()) errors.hoDem = 'Họ đệm là bắt buộc';
    if (!values.ten?.trim()) errors.ten = 'Tên là bắt buộc';
    if (!values.email?.trim()) errors.email = 'Email là bắt buộc';
    else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(values.email)) {
      errors.email = 'Email không hợp lệ';
    }
    if (!values.dienThoai?.trim()) errors.dienThoai = 'Số điện thoại là bắt buộc';
    if (!values.maNganh?.trim()) errors.maNganh = 'Ngành học là bắt buộc';
    if (!values.maTrinhDoDaoTao?.trim()) errors.maTrinhDoDaoTao = 'Trình độ là bắt buộc';
    return errors;
  };

  const createForm = useForm<Partial<Student>>({
    initialValues: getInitialFormValues(),
    validate: validateForm,
    onSubmit: async (values) => {
      try {
        await studentService.create(values);
        setToast({ message: '✅ Thêm học viên thành công!', type: 'success' });
        createModal.close();
        refresh();
      } catch (error: any) {
        setToast({ message: `❌ Lỗi: ${error.message}`, type: 'error' });
      }
    },
  });

  const editForm = useForm<Partial<Student>>({
    initialValues: getInitialFormValues(selectedStudent),
    validate: validateForm,
    onSubmit: async (values) => {
      if (!selectedStudent?.maHV) return;
      try {
        await studentService.update(selectedStudent.maHV, values);
        setToast({ message: '✅ Cập nhật học viên thành công!', type: 'success' });
        editModal.close();
        setSelectedStudent(null);
        refresh();
      } catch (error: any) {
        setToast({ message: `❌ Lỗi: ${error.message}`, type: 'error' });
      }
    },
  });

  // ============================================
  // CRUD HANDLERS
  // ============================================
  const handleCreate = () => {
    createForm.reset();
    createModal.open();
  };

  const handleEdit = (student: Student) => {
    setSelectedStudent(student);
    editModal.open();
  };

  const handleDeleteClick = (student: Student) => {
    setSelectedStudent(student);
    deleteModal.open();
  };

  const handleDeleteConfirm = async () => {
    if (!selectedStudent?.maHV) return;
    try {
      await studentService.delete(selectedStudent.maHV);
      setToast({ message: '✅ Xóa học viên thành công!', type: 'success' });
      deleteModal.close();
      setSelectedStudent(null);
      refresh();
    } catch (error: any) {
      setToast({ message: `❌ Lỗi: ${error.message}`, type: 'error' });
    }
  };

  // ============================================
  // EFFECTS
  // ============================================
  useEffect(() => {
    const loadFilterOptions = async () => {
      try {
        const majorsData = await studentService.getMajorsList();
        setNganhOptions([{ value: '', label: 'Tất cả' }, ...majorsData]);

        const trinhDoData = await studentService.getTrinhDoList();
        setTrinhDoOptions([
          { value: '', label: 'Tất cả' },
          ...trinhDoData.map(t => ({ value: t.maTrinhDoDaoTao, label: t.tenTrinhDo })),
        ]);
      } catch (err) {
        console.error('Error loading filter options:', err);
      }
    };
    loadFilterOptions();
  }, []);

  useEffect(() => {
    const currentYear = new Date().getFullYear();
    const years: SelectOption[] = [{ value: '', label: 'Tất cả' }];
    for (let year = currentYear + 2; year >= currentYear - 10; year--) {
      years.push({ value: year.toString(), label: year.toString() });
    }
    setNamVaoOptions(years);
  }, []);

  useEffect(() => {
    if (selectedStudent && editModal.isOpen) {
      const initialValues = getInitialFormValues(selectedStudent);
      Object.keys(initialValues).forEach((key) => {
        editForm.setFieldValue(key as keyof Student, (initialValues as any)[key]);
      });
    }
  }, [selectedStudent, editModal.isOpen]);

  // ============================================
  // FILTER HANDLERS
  // ============================================
  const handleNamVaoChange = (value: string) => {
    const year = value ? Number(value) : new Date().getFullYear();
    setNamVao(year);
    handleFilter('namVao', year);
  };

  const handleMaNganhChange = (value: string) => {
    setMaNganh(value);
    handleFilter('maNganh', value);
  };

  const handleGioiTinhChange = (value: string) => {
    handleFilter('gioiTinh', value);
  };

  const handleTrinhDoChange = (value: string) => {
    handleFilter('trinhDo', value);
  };

  // ============================================
  // TABLE CONFIGURATION
  // ============================================
  const getStatusBadge = (status: string) => {
    const config = STATUS_CONFIG[status] || { label: status, variant: 'default' as const };
    return <Badge variant={config.variant}>{config.label}</Badge>;
  };

  const columns = useMemo(() => [
    {
      key: 'maHV',
      label: 'Mã học viên',
      render: (student: Student) => (
        <span className="font-semibold text-blue-600">{student.maHV || 'Chưa cấp'}</span>
      ),
    },
    {
      key: 'hoTen',
      label: 'Họ và tên',
      render: (student: Student) => (
        <div>
          <div className="font-medium">{`${student.hoDem} ${student.ten}`}</div>
          <div className="text-xs text-gray-500">{student.email}</div>
        </div>
      ),
    },
    {
      key: 'gioiTinh',
      label: 'Giới tính',
      render: (student: Student) => student.gioiTinh,
    },
    {
      key: 'dienThoai',
      label: 'Điện thoại',
      render: (student: Student) => student.dienThoai,
    },
    {
      key: 'nganh',
      label: 'Ngành học',
      render: (student: Student) => (
        <div>
          <div className="text-sm">
            {student.nganhHoc || student.nganh?.tenNganh || student.maNganh}
          </div>
          <div className="text-xs text-gray-500">Mã: {student.maNganh}</div>
        </div>
      ),
    },
    {
      key: 'namVaoTruong',
      label: 'Năm vào',
      render: (student: Student) => student.namVaotruong || student.namVaoTruong,
    },
    {
      key: 'trangThai',
      label: 'Trạng thái',
      render: (student: Student) => getStatusBadge(student.trangThaiHoc || student.trangThai),
    },
    {
      key: 'actions',
      label: 'Hành động',
      render: (student: Student) => (
        <div className="flex items-center gap-2">
          <button
            onClick={() => handleEdit(student)}
            className="text-blue-600 hover:underline text-sm flex items-center gap-1"
          >
            <PencilIcon className="w-4 h-4" />
            Sửa
          </button>
          <button
            onClick={() => handleDeleteClick(student)}
            className="text-red-600 hover:underline text-sm flex items-center gap-1"
          >
            <TrashIcon className="w-4 h-4" />
            Xóa
          </button>
        </div>
      ),
    },
  ], []);

  const getStudentKey = (student: Student, index: number): string => {
    return student.maHV || `student-${index}-${student.email || student.dienThoai || Math.random()}`;
  };

  // ============================================
  // RENDER HELPERS
  // ============================================
  const renderFormField = (
    form: typeof createForm | typeof editForm,
    fieldName: keyof Student,
    label: string,
    type: string = 'text',
    options?: SelectOption[],
    disabled?: boolean
  ) => {
    const value = form.values[fieldName];
    const error = form.errors[fieldName as string];

    if (type === 'select' && options) {
      return (
        <Select
          label={label}
          value={value as string || ''}
          onChange={(e) => form.handleChange(fieldName, e.target.value)}
          onBlur={() => form.handleBlur(fieldName)}
          options={options}
          error={error}
          disabled={disabled}
        />
      );
    }

    return (
      <Input
        label={label}
        type={type}
        value={value as string || ''}
        onChange={(e) => form.handleChange(fieldName, e.target.value)}
        onBlur={() => form.handleBlur(fieldName)}
        error={error}
        disabled={disabled}
      />
    );
  };

  // ============================================
  // RENDER
  // ============================================
  if (isLoading && students.length === 0) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-600">Đang tải danh sách học viên...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl flex items-center justify-center">
            <UserGroupIcon className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Danh sách học viên</h1>
            <p className="text-sm text-gray-500">Quản lý thông tin học viên</p>
          </div>
        </div>

        <Button variant="primary" onClick={handleCreate}>
          + Thêm học viên
        </Button>
      </div>

      {/* Filters Card */}
      <Card>
        <div className="p-4 space-y-4">
          <div className="flex items-center gap-2 text-gray-700 font-semibold">
            <FunnelIcon className="w-5 h-5" />
            <span>Bộ lọc</span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Tìm kiếm
              </label>
              <div className="relative">
                <MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                <Input
                  type="text"
                  placeholder="Tìm theo mã, tên, email, SĐT..."
                  value={search}
                  onChange={(e) => handleSearch(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>

            <Select
              label="Năm vào trường"
              value={namVao.toString()}
              onChange={(e) => handleNamVaoChange(e.target.value)}
              options={namVaoOptions}
            />

            <Select
              label="Trình độ đào tạo"
              value={filters.trinhDo || ''}
              onChange={(e) => handleTrinhDoChange(e.target.value)}
              options={trinhDoOptions}
            />

            <Select
              label="Giới tính"
              value={filters.gioiTinh || ''}
              onChange={(e) => handleGioiTinhChange(e.target.value)}
              options={GIOI_TINH_OPTIONS}
            />
          </div>

          <Select
            label="Ngành học"
            value={maNganh}
            onChange={(e) => handleMaNganhChange(e.target.value)}
            options={nganhOptions}
          />

          {(search || filters.gioiTinh || filters.trinhDo) && (
            <div className="flex justify-end">
              <Button variant="secondary" onClick={handleClearFilters} size="sm">
                 Xóa bộ lọc
              </Button>
            </div>
          )}
        </div>
      </Card>

      {/* Error Message */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4 text-red-700">
          ⚠️ {error.message}
        </div>
      )}

      {/* Table Card */}
      <Card>
        <div className="p-4">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-semibold text-gray-900">
              Tổng số: <span className="text-blue-600">{meta.total}</span> học viên
              <span className="text-sm text-gray-500 ml-2">
                (Hiển thị {meta.from}-{meta.to})
              </span>
            </h2>
            <Button variant="secondary" onClick={refresh} size="sm">
               Làm mới
            </Button>
          </div>

          <Table
            data={students}
            columns={columns}
            keyExtractor={getStudentKey}
            isLoading={isLoading}
            emptyMessage="Không tìm thấy học viên nào"
          />
        </div>

        {meta.total > 0 && (
          <Pagination
            currentPage={page}
            totalPages={meta.last_page}
            onPageChange={handlePageChange}
            perPage={perPage}
            onPerPageChange={handlePerPageChange}
            total={meta.total}
          />
        )}
      </Card>

      {/* Create Modal */}
      <Modal isOpen={createModal.isOpen} onClose={createModal.close} title="Thêm học viên mới" size="lg">
        <form onSubmit={createForm.handleSubmit}>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {renderFormField(createForm, 'maHV', 'Mã học viên')}
            {renderFormField(createForm, 'hoDem', 'Họ đệm')}
            {renderFormField(createForm, 'ten', 'Tên')}
            {renderFormField(createForm, 'ngaySinh', 'Ngày sinh', 'date')}
            {renderFormField(createForm, 'gioiTinh', 'Giới tính', 'select', GIOI_TINH_OPTIONS)}
            {renderFormField(createForm, 'dienThoai', 'Số điện thoại')}
            {renderFormField(createForm, 'email', 'Email', 'email')}
            {renderFormField(createForm, 'quocTich', 'Quốc tịch')}
            {renderFormField(createForm, 'danToc', 'Dân tộc')}
            {renderFormField(createForm, 'tonGiao', 'Tôn giáo')}
            {renderFormField(createForm, 'maNganh', 'Ngành học', 'select', nganhOptions)}
            {renderFormField(createForm, 'maTrinhDoDaoTao', 'Trình độ đào tạo', 'select', trinhDoOptions)}
            {renderFormField(createForm, 'namVaoTruong', 'Năm vào trường', 'number')}
            {renderFormField(createForm, 'ngayNhapHoc', 'Ngày nhập học', 'date')}
          </div>
          <div className="mt-6 flex justify-end gap-3">
            <Button type="button" variant="secondary" onClick={createModal.close}>
              Hủy
            </Button>
            <Button type="submit" variant="primary" isLoading={createForm.isSubmitting}>
              Thêm học viên
            </Button>
          </div>
        </form>
      </Modal>

      {/* Edit Modal */}
      <Modal isOpen={editModal.isOpen} onClose={editModal.close} title="Chỉnh sửa thông tin học viên" size="lg">
        <form onSubmit={editForm.handleSubmit}>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {renderFormField(editForm, 'maHV', 'Mã học viên', 'text', undefined, true)}
            {renderFormField(editForm, 'hoDem', 'Họ đệm')}
            {renderFormField(editForm, 'ten', 'Tên')}
            {renderFormField(editForm, 'ngaySinh', 'Ngày sinh', 'date')}
            {renderFormField(editForm, 'gioiTinh', 'Giới tính', 'select', GIOI_TINH_OPTIONS)}
            {renderFormField(editForm, 'dienThoai', 'Số điện thoại')}
            {renderFormField(editForm, 'email', 'Email', 'email')}
            {renderFormField(editForm, 'quocTich', 'Quốc tịch')}
            {renderFormField(editForm, 'danToc', 'Dân tộc')}
            {renderFormField(editForm, 'tonGiao', 'Tôn giáo')}
            {renderFormField(editForm, 'maNganh', 'Ngành học', 'select', nganhOptions)}
            {renderFormField(editForm, 'maTrinhDoDaoTao', 'Trình độ đào tạo', 'select', trinhDoOptions)}
            {renderFormField(editForm, 'namVaoTruong', 'Năm vào trường', 'number')}
            {renderFormField(editForm, 'ngayNhapHoc', 'Ngày nhập học', 'date')}
          </div>
          <div className="mt-6 flex justify-end gap-3">
            <Button type="button" variant="secondary" onClick={editModal.close}>
              Hủy
            </Button>
            <Button type="submit" variant="primary" isLoading={editForm.isSubmitting}>
              Cập nhật
            </Button>
          </div>
        </form>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal isOpen={deleteModal.isOpen} onClose={deleteModal.close} title="Xóa học viên" size="sm">
        <div className="space-y-4">
          <p className="text-gray-600">
            Bạn có chắc chắn muốn xóa học viên <strong>{selectedStudent?.maHV}</strong> - <strong>{selectedStudent?.hoDem} {selectedStudent?.ten}</strong>?
          </p>
          <p className="text-sm text-red-600">Hành động này không thể hoàn tác!</p>
          <div className="flex justify-end gap-3">
            <Button variant="secondary" onClick={deleteModal.close}>
              Hủy
            </Button>
            <Button variant="danger" onClick={handleDeleteConfirm}>
              Xóa học viên
            </Button>
          </div>
        </div>
      </Modal>

      {/* Toast Notifications */}
      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}
    </div>
  );
}
